local G = DYCLegendary local modpath = G.modpath local defaultTexture = "fx/snow.tex" local defaultShader = "shaders/particle.ksh" local Round = function(n) return math.floor(n + 0.5) end local TableContains = function(t, value) for k, v in pairs(t) do if v == value then return true end end return false end local TableAdd = function(t, value) if not TableContains(t, value) then table.insert(t, value) end end local TableGetIndex = function(t, value) for k, v in pairs(t) do if v == value then return k end end end local TableRemoveValue = function(t, value) local index = TableGetIndex(t, value) if index then table.remove(t, index) end end local function UnitRand() return math.random() * 2.0 - 1.0 end local function RandomFloat(min, max) max = max or 1.0; min = min or 0; return math.random() * (max - min) + min end local function RandomBoxCoords(r, x, y, z) x = x or 0; y = y or 0; z = z or 0; r = r or 1.0; return x + RandomFloat( - r, r), y + RandomFloat( - r, r), z + RandomFloat( - r, r) end local function RandomSphereCoords(r, x, y, z) x = x or 0; y = y or 0; z = z or 0; r = r or 1.0; local ay = RandomFloat(0x0, 0x2 * math.pi) local ax = RandomFloat( - math.pi / 2.0, math.pi / 2.0) local d = RandomFloat(0x0, r) local xz = d * math.cos(ax) return x + xz * math.cos(ay), y + d * math.sin(ax), z + xz * math.sin(ay) end local function IntColor(r, g, b, a) return {r / 255.0, g / 255.0, b / 255.0, a / 255.0} end local scaleEnvelopeNames = {} local function DYCMakeParticle(data) assert(data.name, "Prefab name is required!" ) local name = data.name local texture = data.texture and modpath..data.texture or defaultTexture local shader = data.shader and modpath..data.shader or defaultShader local bloom = data.bloom or false local rotating = data.rotating or false local followEmitter = data.followEmitter or false local maxParticleNumber = data.maxNumber or 0x78 local number = data.number or 0x3c local numberMult = data.numberMult or 0x1 local maxLifespan = data.maxLifespan or 0x2 local minLifespan = data.minLifespan or 0x1 local blendMode = data.blendMode or BLENDMODE.AlphaBlended local sortOrder = data.sortOrder or 0x0 local layer = data.layer or LAYER_WORLD local acceleration = data.acceleration or Vector3(0x0, - 1.5, 0x0) local drag = data.drag or 0x0 local sheet = data.sheet or nil local velocityFn = data.velocityFn or nil local positionFn = data.positionFn or nil local lifespanFn = data.lifespanFn or nil local angleFn = data.angleFn or nil local angleVelocityFn = data.angleVelocityFn or nil local emitFn = data.emitFn or nil local setPercentageFn = data.setPercentageFn or nil local init = false local function InitEnvelope() if EnvelopeManager and not init then init = true EnvelopeManager:AddColourEnvelope( "dyc_envelope_color_"..name, data.colorEnvelope or {{0x0, IntColor(0xff, 0xff, 0xff, 0xc8)}, {0x1, IntColor(0xff, 0x0, 0x0, 0x0)},}) EnvelopeManager:AddVector2Envelope( "dyc_envelope_scale_"..name, data.scaleEnvelope or {{0x0, {0x1, 0x1}}, {0.5, {0x2, 0x2}}, {0x1, {0x1, 0x1}},}) end end local assets = {Asset( "IMAGE" , texture), Asset( "SHADER" , shader),} local fn = function(Sim) local inst = CreateEntity() local trans = inst.entity:AddTransform() local emitter = inst.entity:AddParticleEmitter() inst.emitter = emitter inst:AddTag( "FX" ) inst:AddTag( "DYCPARTICLE" ) inst.persists = false inst.isDYCParticle = true InitEnvelope() emitter:SetRenderResources(texture, shader) emitter:SetMaxNumParticles(maxParticleNumber) emitter:SetMaxLifetime(maxLifespan) emitter:SetColourEnvelope( "dyc_envelope_color_"..name) emitter:SetScaleEnvelope( "dyc_envelope_scale_"..name) emitter:SetBlendMode(blendMode) emitter:SetSortOrder(sortOrder) emitter:SetLayer(layer) emitter:SetAcceleration(acceleration.x, acceleration.y, acceleration.z) emitter:SetDragCoefficient(drag) emitter:EnableDepthTest(false) if rotating then emitter:SetRotationStatus(true) end if followEmitter then end if bloom then emitter:EnableBloomPass(true) end if sheet then emitter:SetUVFrameSize(1.0 / sheet.w, 1.0 / sheet.h) end inst.particleData = data inst.percentage = 0x1 local interval = 0x1 / number local emissionTimer = 0x0 inst.EmitParticle = function(inst) emissionTimer = emissionTimer + interval if inst.emitDelay and emissionTimer < inst.emitDelay then return end if emitFn then emitFn(inst) return end for i = 0x1, numberMult do local vx, vy, vz = inst:GetParticleVelocity() local lifespan = inst:GetParticleLifespan() local px, py, pz = inst:GetParticlePosition() if not rotating then if sheet then local ru, rv = inst:GetParticleUV() if not inst.stopEmitting then emitter:AddParticleUV(lifespan, px, py, pz, vx, vy, vz, ru, rv ) end else if not inst.stopEmitting then emitter:AddParticle(lifespan, px, py, pz, vx, vy, vz ) end end else local a = inst:GetParticleAngle() local av = inst:GetParticleAngleVelocity() if sheet then local ru, rv = inst:GetParticleUV() if not inst.stopEmitting then emitter:AddRotatingParticleUV(lifespan, px, py, pz, vx, vy, vz, a, av, ru, rv ) end else if not inst.stopEmitting then emitter:AddRotatingParticle(lifespan, px, py, pz, vx, vy, vz, a, av ) end end end end end inst:DoPeriodicTask(interval, function() inst:EmitParticle() if inst.parent and not inst.parentRemoveOverrided then inst:OverrideParentRemove() end end) inst.SetPercentage = function(inst, p) p = p or 0x1 p = Round(p * 100.0) / 100.0 p = math.max(0x0, math.min(p, 0x3e7)) inst.percentage = p if setPercentageFn then setPercentageFn(inst, p) end end inst.SetDelay = function(inst, d) inst.emitDelay = d end inst.AddScaleEnvelope = function(inst, name, envelope) assert(name) assert(envelope) if not TableContains(scaleEnvelopeNames, name) then table.insert(scaleEnvelopeNames, name) EnvelopeManager:AddVector2Envelope(name, envelope) end end inst.GetParticlePosition = function(inst) local px, py, pz = nil, nil, nil if positionFn then px, py, pz = positionFn(inst) else px, py, pz = RandomSphereCoords(0.1) end return px, py, pz end inst.GetParticleVelocity = function(inst) local vx, vy, vz = nil, nil, nil if velocityFn then vx, vy, vz = velocityFn(inst) else vx, vy, vz = RandomBoxCoords(0.1, 0x0, 0.5, 0x0) end return vx, vy, vz end inst.GetParticleAngle = function(inst) local a = nil if angleFn then a = angleFn(inst) else a = RandomFloat(0x0, 0x168) end return a end inst.GetParticleAngleVelocity = function(inst) local av = nil if angleVelocityFn then av = angleVelocityFn(inst) else av = RandomFloat( - 0x2, 0x2) end return av end inst.GetParticleLifespan = function(inst) local lifespan = 0x1 if lifespanFn then lifespan = lifespanFn(inst) else lifespan = minLifespan + (maxLifespan - minLifespan) * UnitRand() end return lifespan end inst.GetParticleUV = function(inst) if not sheet then return 0x1, 0x1 end return math.random(0x0, sheet.w - 0x1) / sheet.w, math.random(0x0, sheet.h - 0x1) / sheet.h end inst.OverrideParentRemove = function(inst) if inst.parent then inst.parentRemoveOverrided = true local parent = inst.parent local oldParentRemove = parent.Remove parent.Remove = function(parent, ...) if inst.parent == parent then local pos = parent:GetPosition() parent:RemoveChild(inst) inst.Transform:SetPosition(pos:Get()) inst:Remove() end oldParentRemove(parent, ...) end end end local oldRemove = inst.Remove inst.Remove = function(inst, delay) if delay then inst:DoTaskInTime(delay, function() inst:Remove() end) return end if inst.removing and inst.removing == 0x1 then return end if inst.removing and inst.removing == 0x0 then oldRemove(inst) return end inst.removing = 0x1 inst.stopEmitting = true inst:DoTaskInTime(maxLifespan, function() inst.removing = 0x0 inst:Remove() end) end return inst end return Prefab( "common/fx/"..name, fn, assets) end return DYCMakeParticle 